import React, { useState } from 'react';

function QuestionForm({ onSubmit }) {
  const [answers, setAnswers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleInputChange = (index, value) => {
    const newAnswers = [...answers];
    newAnswers[index] = value;
    setAnswers(newAnswers);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    const apiKey = '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'; // ⚠️ Reemplaza esto por tu API Key

    try {
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: "gpt-3.5-turbo",
          messages: [
            {
              role: "system",
              content: "Eres un experto en Recursos Humanos que evalúa respuestas de entrevistas."
            },
            {
              role: "user",
              content: `Evalúa las siguientes respuestas del postulante: ${answers.map((a, i) => `Pregunta ${i + 1}: ${a}`).join("; ")}`
            }
          ],
          temperature: 0.7,
          max_tokens: 300
        }),
      });

      const result = await response.json();

      if (!response.ok) {
        throw new Error(result.error?.message || "Error en la respuesta de la API.");
      }

      const analysis = result.choices[0].message.content;
      onSubmit(analysis);
    } catch (err) {
      console.error('Error al conectar con la API', err);
      setError('Hubo un problema al procesar las respuestas.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      {[...Array(8)].map((_, i) => (
        <div key={i} style={{ marginBottom: '10px' }}>
          <label>Pregunta {i + 1}:</label>
          <input
            type="text"
            onChange={(e) => handleInputChange(i, e.target.value)}
            style={{ width: '100%', padding: '8px' }}
          />
        </div>
      ))}

      <button type="submit" disabled={loading} style={{ padding: '10px 20px' }}>
        {loading ? 'Evaluando...' : 'Enviar respuestas'}
      </button>

      {error && <p style={{ color: 'red' }}>{error}</p>}
    </form>
  );
}

export default QuestionForm;
